  "$schema": "http://json-schema.org/draft-07/schema#",
  "title": "draft",
  "description": "R3 agent->spine contract for the draft stage (pi, dealflow-match §4). Bilingual outreach draft. Non-time CTA per R15 (no invented meeting times).",
  "type": "object",
  "required": ["draft_en", "draft_vi"],
  "properties": {
    "subject_en": {"type": ["string", "null"]},
    "subject_vi": {"type": ["string", "null"]},
    "draft_en": {"type": "string"},
    "draft_vi": {"type": "string"}
  }
}

=== schemas/verify.json ===
{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "title": "verify",
  "description": "R3 agent->spine contract for the verify stage (pi, draft-verify LLM-as-judge). `pass` gates matches.status='draft_ready'; on fail, `issues` feed the verify->draft retry (R5).",
  "type": "object",
  "required": ["pass"],
  "properties": {
    "pass": {"type": "boolean"},
    "issues": {"type": "array", "items": {"type": "string"}},
    "checks": {"type": "object"}
  }
}

