  "$schema": "http://json-schema.org/draft-07/schema#",
  "title": "enrich",
  "description": "R3 agent→spine contract for the enrich stage (feynman · entity-enrichment). Permissive: the profile sections vary by entity type; provenance (source_url per populated field) is checked by the §9 audit, not the schema. Relationships feed the edges graph.",
  "type": "object",
  "required": ["entity_type"],
  "properties": {
    "entity_type": {"type": "string"},
    "relationships": {
      "type": "array",
      "items": {
