        "properties": {
          "kind": {"type": "string"},
          "dst_name": {"type": "string"},
          "source_url": {"type": ["string", "null"]},
          "payload": {"type": "object"}
        }
      }
    },
    "collection_summary": {"type": "object"}
  }
}

