export const meta = {
  name: 'spindle-generalization',
  description: 'Autonomously execute the 7-phase deal-flow→spindle platform generalization, gated by the offline A1–A5 North Star harness',
  phases: [
    { title: 'Phase 0', detail: 'Build + verify the offline A1–A5 regression gate (harness)' },
    { title: 'Phase 1', detail: 'Platform migrations: app_id + apps table' },
    { title: 'Phase 2', detail: 'Manifest schema + loader + plugin/port registry + app.yaml' },
    { title: 'Phase 3', detail: 'Extract core/ behind ports.py; cleave Store (highest risk)' },
    { title: 'Phase 4', detail: 'Generalize supervisor: manifest-driven dispatch/DAG/pools' },
    { title: 'Phase 5', detail: 'Move matchmaker into apps/matchmaker; delete shim' },
    { title: 'Phase 6', detail: 'Regression proof: offline gate + full pytest + grep-clean' },
  ],
}

const PLAN = 'docs/superpowers/plans/2026-07-18-agent-data-platform-generalization.md'
const SPEC = 'docs/superpowers/specs/2026-07-18-agent-data-platform-generalization-design.md'

const VERDICT = {
  type: 'object',
  required: ['green', 'summary'],
  properties: {
    green: { type: 'boolean', description: 'true ONLY if you personally ran the gate commands and saw them pass with zero skips' },
    summary: { type: 'string' },
    gate_output: { type: 'string', description: 'the actual tail of the gate command output you observed' },
    failure: { type: 'string', description: 'if not green: the root-cause failure (test name + error), else empty' },
  },
}

// Independent verifier: re-runs the gate itself; never trusts the implementer's claim.
function verifyPrompt(name, extra) {
  return `You are an INDEPENDENT verifier for "${name}" of the spindle generalization. Do NOT trust any prior agent's report — run the checks YOURSELF and report only what you observe.

Run, from the repo root, in order (start Postgres first):
1. \`docker compose up -d postgres\`
2. \`bash scripts/north_star.sh\`  → must PASS with ZERO skipped tests (the script sets NORTH_STAR_REQUIRE_DB=1, so a down/misconfigured DB fails rather than skips). A SKIP is NOT green.
3. \`uv run pytest -q\`  → the full existing suite must stay green.
${extra || ''}

Set green=true ONLY if every command above passed as required. Put the real observed output tail in gate_output. If anything failed, set green=false and put the precise root cause (failing test name + assertion/error) in failure. Change no files.`
}

function repairPrompt(name, verdict) {
  return `The gate for "${name}" is RED. Fix the ROOT CAUSE and get it green.

Observed failure:
${verdict.failure || verdict.summary}

Gate output tail:
${verdict.gate_output || '(none captured)'}

Rules:
- Fix the actual defect. Do NOT weaken, skip, or delete tests or the gate to make it pass (the ONE allowed exception is Phase 5, which legitimately repoints tests/harness/fixtures.py to the manifest/app_id bootstrap per the plan — even then, assertions must not weaken).
- Preserve the single-transaction crash-recovery semantics (SKIP LOCKED lease, LISTEN/NOTIFY, one-txn event+job+saga write) verbatim.
- Re-run \`bash scripts/north_star.sh\` and \`uv run pytest -q\` yourself until both are green with zero skips.
- Commit the fix with a [fix] message ending in the Co-Authored-By trailer for Claude Opus 4.8.
Read ${PLAN} and ${SPEC} for the authoritative contract if you need context.`
}

async function runPhase(name, implementPrompt, opts = {}) {
  phase(name)
  await agent(implementPrompt, { label: `impl:${name}`, phase: name, effort: opts.effort })
  let verdict = await agent(verifyPrompt(name, opts.verifyExtra), { label: `verify:${name}`, phase: name, schema: VERDICT, effort: opts.effort })
  let tries = 0
  while (!verdict.green && tries < 3) {
    await agent(repairPrompt(name, verdict), { label: `repair:${name}:${tries + 1}`, phase: name, effort: opts.effort })
    verdict = await agent(verifyPrompt(name, opts.verifyExtra), { label: `reverify:${name}:${tries + 1}`, phase: name, schema: VERDICT, effort: opts.effort })
    tries++
  }
  return { name, green: verdict.green, tries, summary: verdict.summary, failure: verdict.failure || '' }
}

const GREP_CLEAN = `4. \`grep -rEn 'enrich|extract|draft|startup|matcher|dealflow|onboarding|outreach' spindle/ --include='*.py' | grep -v '# '\`  → must return NOTHING (zero deal-flow strings in the platform core; comments excluded). If it prints matches, green=false.`

const PHASES = [
  {
    name: 'Phase 0',
    effort: 'high',
    prompt: `Implement Phase 0 (Tasks 0.1–0.5) of ${PLAN} EXACTLY as written. The plan's code was already reviewed and corrected — follow it verbatim; adjust a line only if a real API signature in spine/ differs from the snippet (verify against spine/store.py, spine/supervisor.py, spine/transport.py, api/app.py).

Create: tests/harness/__init__.py, tests/harness/db.py, tests/harness/replay_launcher.py, tests/harness/fixtures.py, tests/test_north_star.py, scripts/north_star.sh; modify pyproject.toml (register the north_star marker) and README.md (Tests section). Make scripts/north_star.sh executable.

Start Postgres (\`docker compose up -d postgres\`), then ensure \`bash scripts/north_star.sh\` PASSES green with ZERO skipped tests, and \`uv run pytest -q\` stays green. Commit per the plan's per-task [test] commit steps (Co-Authored-By trailer for Claude Opus 4.8). This harness is the load-bearing gate for every later phase — it must be correct and deterministic (rerun it 3× to confirm stable counts).`,
  },
  {
    name: 'Phase 1',
    prompt: `Implement Phase 1 of ${PLAN} ("Extraction Roadmap → Phase 1") using the locked "Resolved seam decisions" and ${SPEC} §B. Create migrations/004_platform_appid.sql: add an app_id column to jobs/events/saga_instances/artifacts (backfill existing rows to 'matchmaker'), add the apps table (app_id PK, name, manifest_sha, registered_at), and widen the idempotency uniques to (app_id, saga_id, …). Defaults/backfill MUST keep every existing spine/store.py method working unchanged (they don't know app_id yet), so the North Star harness — which applies migrations/*.sql into a fresh DB — stays green. Do not touch Python yet. Verify \`bash scripts/north_star.sh\` and \`uv run pytest -q\` are green, then commit with a [feat] message + Co-Authored-By trailer.`,
  },
  {
    name: 'Phase 2',
    prompt: `Implement Phase 2 of ${PLAN} ("Extraction Roadmap → Phase 2") + Seam 1 + ${SPEC} §C. Create spindle/ package: spindle/manifest/schema.json (manifest JSON Schema), spindle/manifest/loader.py (load+validate app.yaml → in-memory saga DAGs + AgentSpecs), spindle/registry.py (the @stage, @port, @agent_stage decorators from Seam 1). Create apps/matchmaker/app.yaml mirroring today's two sagas (onboarding: enrich→extract→link; outreach: filter→match→draft→verify) — cross-check stage names against spine/sagas.py ONBOARDING_STAGES and spine/outreach.py OUTREACH_STAGES (note: there is NO 'ingest' stage today — start onboarding at enrich). Add pure unit tests (no DB) asserting the loader yields those exact stage lists. Nothing wires into the supervisor yet, so the harness path is unchanged. Verify \`bash scripts/north_star.sh\` and \`uv run pytest -q\` green; commit [feat] + trailer.`,
  },
  {
    name: 'Phase 3',
    effort: 'high',
    prompt: `Implement Phase 3 of ${PLAN} ("Extraction Roadmap → Phase 3") + Seam 3 + ${SPEC} §E. This is the HIGHEST-RISK phase — proceed method-by-method and run the gate after each move.

Create spindle/core/ (saga engine, DAG advance, reconciler — pure, NO I/O imports), spindle/ports.py (Protocols: Store, RuntimeLauncher, Notifier, Clock), spindle/adapters/postgres_store.py (PLATFORM-only store: jobs/events/sagas/artifacts, every method gains an app_id param, single-transaction finish_stage/complete_and_fanout write ONLY queue+event+saga+artifact rows — NEVER app tables, preserving SKIP LOCKED + LISTEN/NOTIFY + the one-txn event+job+saga write VERBATIM), apps/matchmaker/store.py (app entity/edge/match accessors). Add a core import-lint test asserting spindle/core imports neither adapters nor asyncpg.

CRITICAL for keeping the harness green mid-cleave: keep the existing spine.store.Store as a THIN SHIM delegating to the split stores, so nothing breaks until Phase 5 removes it. The North Star harness must stay green throughout. Verify \`bash scripts/north_star.sh\` and \`uv run pytest -q\`; commit [refactor] + trailer.`,
    verifyExtra: `Additionally confirm the core import-lint test exists and passes (spindle/core must not import adapters or asyncpg).`,
  },
  {
    name: 'Phase 4',
    effort: 'high',
    prompt: `Implement Phase 4 of ${PLAN} ("Extraction Roadmap → Phase 4") + Seams 1&2 + ${SPEC} §D. Move spine/supervisor.py logic to spindle/app/supervisor.py and make the four §D changes: (1) replace the _dispatch if/elif over stage names with manifest resolution stage→{run, port?} — run:code calls the @stage fn, run:<agent> runs the pooled worker then hands RpcResult.data to the AgentStageHandler's validate/persist_and_advance (Seam 1); (2) replace the hardcoded _NEXT/next_stage map and the hand-written fan-out with the DAG engine reading the saga list from the manifest, with fan-out (next_jobs) and on_reject:{retry,max,then:dead} as generic edges (Seam 2) — match's per-partner fan-out and verify's reject→rearm→dead-letter become handler/DAG behavior, NOT special cases; (3) key pools by (runtime, skill, model) with LOAD-TIME tool/model compatibility validation (mismatch = hard manifest error, risk R-a); (4) carry app_id through reconcile/LISTEN-NOTIFY/reclaim/dead-letter. The North Star harness now drives the fully-generic supervisor over the manifest — keep it green. Verify \`bash scripts/north_star.sh\` and \`uv run pytest -q\`; commit [refactor] + trailer.`,
    verifyExtra: GREP_CLEAN,
  },
  {
    name: 'Phase 5',
    effort: 'high',
    prompt: `Implement Phase 5 of ${PLAN} ("Extraction Roadmap → Phase 5") + ${SPEC} §F. Move the deterministic bodies of spine/sagas.py + spine/outreach.py into apps/matchmaker/plugin.py: @stage for code stages (link, filter) and @agent_stage handlers (EnrichStage, ExtractStage, MatchStage, DraftStage, VerifyStage) carrying build_prompt/validate/persist_and_advance per Seam 1. Move spine/matcher/ into apps/matchmaker/ behind @port("matcher"). Move entities/edges/matches DDL into apps/matchmaker/migrations/. DELETE the spine.store.Store shim and any remaining spine/ deal-flow modules now fully migrated.

You MAY repoint tests/harness/fixtures.py to bootstrap via the manifest loader + app_id='matchmaker' (the plan explicitly allows this) — but the ReplayLauncher stays app-agnostic and NO A1–A5 assertion may weaken. Verify \`bash scripts/north_star.sh\` and \`uv run pytest -q\` green; commit [refactor] + trailer.`,
    verifyExtra: GREP_CLEAN,
  },
  {
    name: 'Phase 6',
    effort: 'high',
    prompt: `Implement Phase 6 of ${PLAN} ("Extraction Roadmap → Phase 6") — the regression proof, OFFLINE only. Do NOT run live feynman/pi agents, do NOT make web calls, do NOT spend money — the live cold-boot is a manual human follow-up, not part of this run.

Confirm the full definition-of-done holds: \`bash scripts/north_star.sh\` green with zero skips, \`uv run pytest -q\` fully green, and \`grep -rEn 'enrich|extract|draft|startup|matcher|dealflow|onboarding|outreach' spindle/ --include='*.py' | grep -v '# '\` returns NOTHING (zero deal-flow strings in the platform core). Write a short docs/superpowers/plans/PHASE6-REGRESSION.md summarizing what passed and listing the exact manual live-cold-boot command sequence (from the README acceptance run) the human should run to close A1–A5 with real agents. Commit [docs] + trailer.`,
    verifyExtra: GREP_CLEAN,
  },
]

const results = []
for (const p of PHASES) {
  const r = await runPhase(p.name, p.prompt, { effort: p.effort, verifyExtra: p.verifyExtra })
  results.push(r)
  log(`${p.name}: ${r.green ? 'GREEN' : 'RED'} after ${r.tries} repair(s) — ${r.summary}`)
  if (!r.green) {
    log(`⛔ STOP: ${p.name} gate could not be made green after ${r.tries} repairs. Halting per full-autonomous stop condition.`)
    break
  }
}
return results
